# For a bijective encoding, we need to preserve all 8 bits
# If we shift left by 2, we lose 2 bits - collision is inevitable
# Maybe we should NOT apply the mask until after the XOR!

def test_shift_amount(shift):
    """Test if a given shift amount allows reversible encoding"""
    def encode(data):
        result = []
        for b in data:
            shifted = (b << shift) & 0xFF
            result.append(shifted ^ 0xAA)
        return bytes(result)

    def decode(encoded):
        result = []
        for b in encoded:
            unxored = b ^ 0xAA
            shifted = (unxored >> shift) & 0xFF
            result.append(shifted)
        return bytes(result)

    # Test all bytes
    failures = 0
    for i in range(256):
        original = bytes([i])
        try:
            decoded = decode(encode(original))
            if decoded != original:
                failures += 1
                if failures <= 3:
                    print(f"  Shift {shift}: byte {i} -> {encode(original)[0]} -> {decoded[0]}")
        except:
            failures += 1

    return failures == 0

# Test different shift amounts
print("Testing different shift amounts:")
for shift in range(1, 8):
    works = test_shift_amount(shift)
    print(f"Shift {shift}: {'WORKS' if works else 'fails'}")
